PyTypeObject* DoInitWrapperVector(const UScriptStruct* InStruct, PyTypeObject* InSuperType)
{
	if (InStruct == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedStructType(InStruct))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedStructType(InStruct));
	}

	PyTypeObject* PyType = &UPyWrapperVectorType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperStructType;
	PyType->tp_init = (initproc)&FFuncs_Vector::Init;
	PyType->tp_methods = FUPyWrapperVectorPyMethodDefs;
	PyType->tp_getset = FUPyWrapperVectorGetSets;
	PyType->tp_richcompare = (richcmpfunc)&FFuncs_Vector::RichCmp;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNumberFuncs_Vector::Op_add;
	PyNumber.nb_inplace_add = (binaryfunc)&FNumberFuncs_Vector::Op_iadd;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNumberFuncs_Vector::Op_imul;
	PyNumber.nb_inplace_subtract = (binaryfunc)&FNumberFuncs_Vector::Op_isub;
	PyNumber.nb_multiply = (binaryfunc)&FNumberFuncs_Vector::Op_mul;
	PyNumber.nb_negative = (unaryfunc)&FNumberFuncs_Vector::Op_neg;
	PyNumber.nb_or = (binaryfunc)&FNumberFuncs_Vector::Op_or;
	PyNumber.nb_subtract = (binaryfunc)&FNumberFuncs_Vector::Op_sub;
	PyNumber.nb_true_divide = (binaryfunc)&FNumberFuncs_Vector::Op_truediv;
	PyNumber.nb_xor = (binaryfunc)&FNumberFuncs_Vector::Op_xor;
	PyType->tp_as_number = &PyNumber;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyConstantDef::AddConstantsToType(FConstants_Vector::Table(), PyType);
		FUPyWrapperTypeRegistry::Get().RegisterWrappedStructType(InStruct, PyType);
		return PyType;
	}

	return nullptr;

}

void InitializeUPyWrapperVector(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterInlineStructFactory(StaticCastSharedRef<const IUPyWrapperInlineStructFactory>(MakeShared<TUPyWrapperInlineStructFactory<FVector>>()));
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedStructCreateFunc(TBaseStructure<FVector>::Get(), DoInitWrapperVector);
}

PyObject* FUPyWrapperVector::CreateInstance(const FVector& InValue, const FUPyWrapperOwnerContext& InOwnerContext, const EUPyConversionMethod InConversionMethod)
{
	return (PyObject*)FUPyWrapperStructFactory::Get().CreateInstance(&UPyWrapperVectorType, TBaseStructure<FVector>::Get(), (void*)&InValue, InOwnerContext, InConversionMethod);
}

FUPyWrapperVector* UPyIsVector(PyObject* InSelf)
{
	if (InSelf && PyObject_TypeCheck(InSelf, &UPyWrapperVectorType))
	{
		return (FUPyWrapperVector*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult NativizeStructInstance(PyObject* PyObj, FVector& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperVector* PyVector = UPyIsVector(PyObj))
		{
			OutVal = *PyVector->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("NativizeStructInstance"), *FString::Printf(TEXT("Cannot nativize '%s' as 'FVector'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
	
	FUPyConversionResult PythonizeStructInstance(const FVector& InVal, PyObject*& OutPyObj, const ESetErrorState SetErrorState)
	{
		OutPyObj = FUPyWrapperVector::CreateInstance(InVal, FUPyWrapperOwnerContext(), EUPyConversionMethod::Copy);
		return FUPyConversionResult::Success();
	}
}
